// Split the batch into one item per topic
const topics = $input.first().json.topics ?? [];
return topics.map(t => ({ json: t }));

const topic = $('Loop').item.json;
const quran = $input.first().json.search?.results ?? [];
const verses = quran.map(r => {
  const [s, a] = r.verse_key.split(':').map(Number);
  return { surah: s, ayah: a, arabic: r.text, english: r.translations?.[0]?.text ?? '', reference: `Quran ${s}:${a}`, url: `https://quran.com/${s}/${a}` };
});
return [{ json: { ...topic, __verses: verses } }];

const topic = $('Attach verses').item.json;
const body = $input.first().json;
const raw = body?.data ?? [];
const hadiths = raw.map(h => ({ collection: h.collection, hadithNumber: h.hadithNumber, arabic: h.hadithArabic ?? '', english: h.hadithEnglish ?? '', reference: `${h.collection} ${h.hadithNumber}`, url: `https://sunnah.com/${h.collection}:${h.hadithNumber}` }));
return [{ json: { ...topic, __hadiths: hadiths } }];

const topic = $input.first().json;
const verses = topic.__verses ?? [];
const hadiths = topic.__hadiths ?? [];
const SYSTEM = `You are a meticulous Muslim writer producing a single da'wah blog post for rassoul.org.

Non-negotiable rules:
1. EVERY hadith you reference MUST come from the Verified hadiths list. Cite inline using <Citation source="..." book="..." number="..." href="..." />. Do NOT invent, paraphrase from memory, or attribute hadiths to sources not in the list.
2. EVERY Quran verse you reference MUST come from the Verified Quran verses list. Cite the same way.
3. HARD RULE — attribution requires citation. Never write "the Prophet said", "Allah says", or similar speech-attribution phrases without an adjacent <Citation> tag, <Arabic> block, or link to sunnah.com/quran.com.
4. Use <Arabic>{"النص العربي"}</Arabic> for Arabic. Always wrap in JSX string literal quotes.
5. Voice: respectful, scholarly, accessible. No exclamations, no emojis, no preaching.
6. Use ﷺ after the Prophet's name.
7. Output ONLY the MDX body. No frontmatter, no commentary.
8. Structure: open with a 1–2 sentence answer to the search intent. Then 3–6 H2 sections. End with a Sources H2 listing citations as plain markdown links.
9. Length: 900–1600 words.
10. If sources don't cover it, output ONLY the string NO_SOURCES.
11. NEVER use JSON-escaped quotes like source=\"X\". Use plain source="X".`;
const sources = [];
if (verses.length) { sources.push('## Verified Quran verses'); for (const v of verses) { sources.push(`- ${v.reference} — ${v.url}`); if (v.english) sources.push(`  English: "${v.english.replace(/\s+/g,' ').trim()}"`); } }
if (hadiths.length) { sources.push('', '## Verified hadiths'); for (const h of hadiths) { sources.push(`- ${h.reference} — ${h.url}`); if (h.english) sources.push(`  English: "${h.english.replace(/\s+/g,' ').trim().slice(0,500)}"`); } }
if (!sources.length) sources.push('No sources retrieved. Return NO_SOURCES.');
const user = `Topic: ${topic.title}
Cluster: ${topic.cluster}
Keyword: "${topic.keyword}"

${sources.join('
')}

Write the MDX body now, following every rule.`;
return [{ json: { ...topic, __system: SYSTEM, __user: user } }];

// Post-process: auto-fix MDX bugs, validate, compile MDX to HTML
const topic = $('Build prompt').item.json;
const deepseek = $input.first().json;
const verses = topic.__verses ?? [];
const hadiths = topic.__hadiths ?? [];

const raw = deepseek?.choices?.[0]?.message?.content?.trim();
if (!raw || raw === 'NO_SOURCES') return [{ json: { ...topic, __status: 'failed', __notes: ['Model returned empty or NO_SOURCES.'] } }];

function fixArabic(m) { let n=0; const f = m.replace(/<Arabic>([\s\S]+?)<\/Arabic>/g, (w, inner) => { const t = inner.trim(); if (/^\{\s*("[^"]*"|'[^']*')\s*\}$/.test(t)) return w; let v = t.replace(/^\{\s*["'`]?/,'').replace(/["'`]?\s*\}$/,'').trim(); if (!v) return w; n++; return `<Arabic>{"${v.replace(/\\/g,'\\\\').replace(/"/g,'\\"')}"}</Arabic>`; }); return {fixed: f, count: n}; }
function fixAutolinks(m) { let n=0; const f = m.replace(/<(https?:\/\/[^>\s]+)>/g, (_, u) => { n++; return u; }); return {fixed: f, count: n}; }
function fixEscapedAttrs(m) { let n=0; const f = m.replace(/<([A-Z][A-Za-z]*)\b([^>]*?)\/?>/g, (w, t, a) => { if (!a.includes('\\"')) return w; n++; return w.replace(a, a.replace(/\\"/g,'"')); }); return {fixed: f, count: n}; }

const a = fixArabic(raw); const b = fixAutolinks(a.fixed); const c = fixEscapedAttrs(b.fixed); const mdx = c.fixed;
const autofixTotal = a.count + b.count + c.count;

// Validate <Citation> refs match fetched sources
const allowed = new Set();
for (const v of verses) allowed.add(v.reference.toLowerCase());
for (const h of hadiths) allowed.add(h.reference.toLowerCase());
const notes = [];
let valid = true;
const citeRe = /<Citation\s+([^/]*?)\/>/g;
let cm;
while ((cm = citeRe.exec(mdx))) {
  const attrs = cm[1];
  const src = (attrs.match(/source="([^"]+)"/) ?? [])[1] ?? '';
  const bk = (attrs.match(/book="([^"]+)"/) ?? [])[1] ?? '';
  const nm = (attrs.match(/number="([^"]+)"/) ?? [])[1] ?? '';
  const ref = [src, bk, nm].filter(Boolean).join(' ').trim().toLowerCase();
  if (ref) {
    const toks = ref.split(/\s+/);
    const ok = [...allowed].some(al => toks.every(t => al.includes(t)));
    if (!ok) { valid = false; notes.push(`Unverified citation: "${ref}"`); }
  }
}
// Attribution guard
const attrPatterns = [/\b(?:the\s+)?(?:prophet|messenger|he)\s*(?:ﷺ|\(saw\)|\(pbuh\))?\s+(said|narrated|reported|taught|told|mentioned|explained|warned|advised|instructed|declared|stated|informed|described|promised|ordered|commanded|prohibited|forbade)\b/gi, /\b(?:allah(?:'s)?|the\s+almighty|the\s+quran|the\s+qur'an)\s+(said|says|tells|told|reveals|revealed|declares|declared|commands|commanded)\b/gi];
const seenAttr = new Set();
for (const re of attrPatterns) { let am; while ((am = re.exec(mdx))) { const start = am.index; const win = mdx.slice(start, Math.min(mdx.length, start + 500)); const hasAnchor = /<Citation\b/.test(win) || /<Arabic\b/.test(win) || /https?:\/\/sunnah\.com\//.test(win) || /https?:\/\/quran\.com\//.test(win) || /\([^)]*(?:sahih|bukhari|muslim|tirmidhi|abu\s*dawud|nasa|ibn\s*majah|sunan|musnad|quran|surah|ayah)[^)]*\)/i.test(win); if (!hasAnchor) { const snip = mdx.slice(Math.max(0, start-20), Math.min(mdx.length, start+120)).replace(/\s+/g,' ').trim(); const k = snip.toLowerCase(); if (!seenAttr.has(k)) { seenAttr.add(k); valid = false; notes.push(`Uncited attribution: "…${snip}…"`); } } } }
if (autofixTotal > 0) notes.push(`Auto-fixed ${autofixTotal} MDX bug(s).`);

// Compile MDX to HTML (lightweight — matches the seed script's approach)
function mdxToHtml(m) {
  let s = m.replace(/<Arabic>\s*\{"([^"]+)"\}\s*<\/Arabic>/g, '<div class="arabic-block">$1</div>')
           .replace(/<Citation\s+([^/]*?)\/>/g, (_, a) => { const src = /source="([^"]+)"/.exec(a)?.[1] ?? ''; const bk = /book="([^"]+)"/.exec(a)?.[1] ?? ''; const nm = /number="([^"]+)"/.exec(a)?.[1] ?? ''; const hf = /href="([^"]+)"/.exec(a)?.[1] ?? '#'; const lbl = [src, bk, nm].filter(Boolean).join(' '); return `<a href="${hf}" class="citation" target="_blank" rel="noreferrer">${lbl}</a>`; });
  let out = s.replace(/^### (.+)$/gm, '<h3>$1</h3>').replace(/^## (.+)$/gm, '<h2>$1</h2>').replace(/^# (.+)$/gm, '<h1>$1</h1>').replace(/\*\*([^*]+)\*\*/g, '<strong>$1</strong>').replace(/\*([^*]+)\*/g, '<em>$1</em>').replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2">$1</a>').replace(/^- (.+)$/gm, '<li>$1</li>');
  out = out.replace(/(<li>[\s\S]+?<\/li>\n?)+/g, '<ul>$&</ul>');
  const blocks = out.split(/\n\n+/).map(b => { const t = b.trim(); if (!t) return ''; if (/^<(h[1-6]|ul|ol|div|p|blockquote|pre|figure|table|a)/.test(t)) return t; return `<p>${t.replace(/\n/g,' ')}</p>`; });
  return blocks.join('\n');
}

const html = mdxToHtml(mdx);
// Extract citation URLs from mdx for the citations field
const citations = [];
const urlRe = /https?:\/\/(?:sunnah|quran)\.com\/[^\s"'<>)]+/g;
let um;
while ((um = urlRe.exec(mdx))) citations.push(um[0]);

const desc = `${topic.title} — sourced from authentic Quran and hadith references.`;
return [{ json: { ...topic, __status: valid ? 'published' : 'needs_review', __notes: notes, __body: { slug: topic.slug, cluster: topic.cluster, title: topic.title, description: desc, keyword: topic.keyword, html: html, rawMdx: mdx, citations: [...new Set(citations)], reviewNotes: notes, status: valid ? 'published' : 'needs_review' } } }];

const results = $input.all().map(i => i.json);
const published = results.filter(r => r.__status === 'published').length;
const needsReview = results.filter(r => r.__status === 'needs_review').length;
const failed = results.filter(r => r.__status === 'failed').length;
return [{ json: { published, needs_review: needsReview, failed, total: results.length } }];

